function extractResumeName(text=''){
  const shared=window.RoleDeskResume?.extractName?.(text);if(shared)return shared;
  const lines=String(text).split(/\r?\n/).map(line=>line.trim()).filter(Boolean).slice(0,12);
  const labeled=lines.map(line=>line.match(/^(?:full\s+name|name)\s*[:\-]\s*([a-z][a-z .'-]{2,60})$/i)).find(Boolean);
  if(labeled)return labeled[1].trim();
  return lines.find(line=>/^[a-z][a-z .'-]{2,60}$/i.test(line)&&line.split(/\s+/).length>=2&&line.split(/\s+/).length<=4&&!/resume|curriculum|designer|developer|manager|profile|summary/i.test(line))||'';
}
function emailNameFallback(email=''){
  let local=String(email).split('@')[0].replace(/^(hello|contact|connect|work|info)[._-]+/i,'').replace(/\d+$/,'');
  local=local.replace(/[._-]+/g,' ').replace(/([a-z])([A-Z])/g,'$1 $2').trim();
  return local?local.replace(/\b\w/g,char=>char.toUpperCase()):'';
}
function resolvedUserName(){
  const direct=[resumeProfile?.fullName,resumeProfile?.full_name,resumeProfile?.displayName,resumeProfile?.display_name].find(value=>{const name=String(value||'').trim();return name&&!/^\[?your name\]?$/i.test(name)&&name!=='Needs review'});
  if(direct)return String(direct).trim();
  const fromResume=extractResumeName(resumeProfile?.rawText||resumeProfile?.text||'');if(fromResume)return fromResume;
  const email=$('#workEmail')?.value||$('#emailFrom')?.value||($('#signedInEmail')?.textContent.includes('@')?$('#signedInEmail').textContent:'');
  return emailNameFallback(email)||(resumeProfile?.rawText||resumeProfile?.text?'Needs review':'[Your name]');
}
